test_metadata_author_meta() {
  # Extract author from <meta name='author'> tag
  local output
  output=$(html_to_markdown convert)

  local val_content
  val_content=$(echo "$output" | jq -r '.content')
  assert_not_empty "$val_content" 'content'
  local val_metadata_author
  val_metadata_author=$(echo "$output" | jq -r '.metadata.document.author')
  assert_equals "$val_metadata_author" 'Jane Doe' 'metadata.author'
}

